document.addEventListener("DOMContentLoaded",()=>{const o=document.getElementById("countdown");if(!o)return;const d=window.otpExpiredTime*1e3,i=document.getElementById("timerContainer"),s=document.getElementById("resendContainer"),r=setInterval(function(){const c=new Date().getTime(),e=d-c;if(e<0){clearInterval(r),i.classList.add("hidden"),s.classList.remove("hidden");return}const n=Math.floor(e%(1e3*60*60)/(1e3*60)),t=Math.floor(e%(1e3*60)/1e3);o.innerHTML=(n<10?"0"+n:n)+":"+(t<10?"0"+t:t)},1e3)});
